import java.util.Arrays;
import java.util.Comparator;

public class Solution {

    private static final long MOD = 1_000_000_007L;

    /**
     * Modular exponentiation: (base^exp) % mod
     */
    private static long power(long base, long exp) {
        long res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 == 1) {
                res = (res * base) % MOD;
            }
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }

    // Helper class to store segment properties
    private static class Segment {
        long a1; // count of 1s
        long a0; // count of 0s

        Segment(long a1, long a0) {
            this.a1 = a1;
            this.a0 = a0;
        }
    }

    public static long solve(long[] nums1, long[] nums0) {
        int n = nums1.length;
        Segment[] segments = new Segment[n];

        for (int i = 0; i < n; i++) {
            segments[i] = new Segment(nums1[i], nums0[i]);
        }

        // Custom sorting: P_i comes before P_j if P_i P_j > P_j P_i
        // Based on the reference implementation's logic:
        // 1. Prefer larger a1 (more leading ones).
        // 2. If a1s are equal, prefer larger a0 (more trailing zeros) 
        //    -- This matches the heuristic used in the reference solution for stability/maximal value.
        Arrays.sort(segments, new Comparator<Segment>() {
            @Override
            public int compare(Segment i, Segment j) {
                // Compare based on a1 first (descending)
                if (i.a1 != j.a1) {
                    return Long.compare(j.a1, i.a1); // j.a1 - i.a1
                }
                // If a1s are equal, compare based on a0 (descending)
                return Long.compare(j.a0, i.a0); // j.a0 - i.a0
