import java.util.Arrays;
import java.util.Comparator;
import java.util.stream.IntStream;

public class Solution {

    private static final long MOD = 1_000_000_007L;

    /**
     * Modular exponentiation: (base^exp) % mod
     */
    private static long power(long base, long exp, long mod) {
        long res = 1;
        base %= mod;
        while (exp > 0) {
            if (exp % 2 == 1) {
                res = (res * base) % mod;
            }
            base = (base * base) % mod;
            exp /= 2;
        }
        return res;
    }

    public static long solve(long[] nums1, long[] nums0) {
        int n = nums1.length;

        // 1. Create an array of indices [0, 1, ..., n-1]
        Integer[] indices = IntStream.range(0, n).boxed().toArray(Integer[]::new);

        // 2. Sort the indices based on the greedy criterion: 
        // Primary key: nums1[i] (count of '1's) descending.
        // Secondary key: nums0[i] (count of '0's) descending.
        Arrays.sort(indices, new Comparator<Integer>() {
            @Override
            public int compare(Integer i, Integer j) {
                long a1 = nums1[i];
                long a0 = nums0[i];
                long b1 = nums1[j];
                long b0 = nums0[j];

                // Sort descending by a1 (b1 - a1)
                if (a1 != b1) {
                    return Long.compare(b1, a1);
                }

                // If a1 are equal, sort descending by a0 (b0 - a0)
                return Long.compare(b0, a0);
            }
        });

        long totalValue = 0;

        // 3. Calculate the total value in the optimal order
        for (int i : indices) {
