import java.util.Arrays;
import java.util.Comparator;

public class Solution {
    private static final long MOD = 1000000007L;

    /**
     * Modular exponentiation: (base^exp) % mod
     */
    private static long power(long base, long exp) {
        long res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 == 1) {
                res = (res * base) % MOD;
            }
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }

    public static long solve(long[] nums1, long[] nums0) {
        int n = nums1.length;

        // 1. Prepare indices for sorting
        Integer[] indices = new Integer[n];
        for (int i = 0; i < n; i++) {
            indices[i] = i;
        }

        // 2. Sort the indices based on lexicographical comparison P_i P_j vs P_j P_i
        Arrays.sort(indices, new Comparator<Integer>() {
            @Override
            public int compare(Integer i, Integer j) {
                long a1 = nums1[i];
                long a0 = nums0[i];
                long b1 = nums1[j];
                long b0 = nums0[j];

                // Construct P_i P_j
                StringBuilder sb_ij = new StringBuilder();
                for (int k = 0; k < a1; k++) sb_ij.append('1');
                for (int k = 0; k < a0; k++) sb_ij.append('0');
                for (int k = 0; k < b1; k++) sb_ij.append('1');
                for (int k = 0; k < b0; k++) sb_ij.append('0');
                String s_ij = sb_ij.toString();

                // Construct P_j P_i
                StringBuilder sb_ji = new StringBuilder();
                for (int k = 0; k < b1; k++) sb_ji.append('1');
                for (int k = 0; k < b0; k++) sb_ji.append('0');
                for (int k = 0; k < a1; k++) sb_ji.append('1');
                for (int k = 0; k < a0; k++) sb_ji.append('0');
                String s_ji = sb_ji.toString();

                // We want descending order based on string value (lexicographically larger first).
                // compare(i, j) should return negative if i comes before j.
                // If s_ij > s_ji, i comes before j. s_ij.compareTo(s_ji) > 0. We return -1.
                return s_ji.compareTo(s_ij);
            }
        });

        // 3. Calculate the total value
        long totalValue = 0;

        for (int i : indices) {
            long a1 = nums1[i];
            long a0 = nums0[i];
            long Li = a1 + a0;

            // Calculate Value(P_i) = (2^a1 - 1) * 2^a0 mod M

            // term1 = 2^a1 - 1 mod M
            long term1;
            if (a1 == 0) {
                term1 = 0;
            } else {
                long twoPowA1 = power(2, a1);
                term1 = (twoPowA1 - 1 + MOD) % MOD;
            }

            // term2 = 2^a0 mod M
            long term2 = power(2, a0);

            // Vi = Value(P_i) mod M
            long Vi = (term1 * term2) % MOD;

            // Update total value: V_new = (V_prev * 2^Li + Vi) mod M

            // V_prev * 2^Li mod M
            long term_prev_shifted = (totalValue * power(2, Li)) % MOD;

            totalValue = (term_prev_shifted + Vi) % MOD;
        }

        return totalValue;
    }
}
