function solve(nums1, nums0) {
    const MOD = 1000000007n;

    /**
     * Modular exponentiation: (base^exp) % mod
     * Uses BigInt for safe calculation.
     */
    function power(base, exp, mod) {
        let res = 1n;
        base = base % mod;
        let e = BigInt(exp);

        while (e > 0n) {
            if (e % 2n === 1n) {
                res = (res * base) % mod;
            }
            base = (base * base) % mod;
            e = e / 2n;
        }
        return res;
    }

    const n = nums1.length;
    const indices = Array.from({ length: n }, (_, i) => i);

    // Custom sorting comparator based on lexicographical comparison of P_i P_j vs P_j P_i
    // Returns < 0 if i should come before j, > 0 if j should come before i, 0 otherwise.
    indices.sort((i, j) => {
        const a1 = nums1[i];
        const a0 = nums0[i];
        const b1 = nums1[j];
        const b0 = nums0[j];

        // 1. Compare number of '1's (a1 vs b1)
        // Prefer more '1's first. If a1 > b1, i comes before j (return -1).
        if (a1 !== b1) {
            return b1 - a1;
        }

        // 2. If '1' counts are equal (a1 = b1), compare number of '0's (a0 vs b0)
        // We prefer the order that yields a lexicographically larger string when comparing 0^a0 1^k 0^b0 vs 0^b0 1^k 0^a0.
        // This requires sorting by decreasing a0 (i.e., b0 - a0).
        if (a0 !== b0) {
            return b0 - a0;
        }

        return 0; // Fragments are equivalent
    });

    let totalValue = 0n;

    for (const i of indices) {
        const a1 = nums1[i];
        const a0 = nums0[i];
        const Li = a1 + a0;

        // 1. Calculate Value(P_i) = 2^a1 - 1 mod M
        let Vi;
        if (a1 === 0) {
            // If a1=0, P_i is all zeros, value is 0. 2^0 - 1 = 0.
            Vi = 0n;
        } else {
            const twoPowA1 = power(2n, a1, MOD);
            // Vi = (2^a1 - 1) % M
            Vi = (twoPowA1 - 1n + MOD) % MOD;
        }

        // 2. Calculate 2^Li mod M
        const twoPowLi = power(2n, Li, MOD);

        // 3. Update total value: V = (V * 2^Li + Vi) % M
        totalValue = (totalValue * twoPowLi) % MOD;
        totalValue = (totalValue + Vi) % MOD;
